// Extract summary data from WayinVideo
const summaryData = $('4. WayinVideo — Get Summary Results').item.json.data;

const summary = summaryData.summary || '';
const highlights = Array.isArray(summaryData.highlights)
  ? summaryData.highlights.map((h, i) => `${i + 1}. ${h.desc}`).join('\n')
  : '';
const tags = Array.isArray(summaryData.tags)
  ? summaryData.tags.join(', ')
  : '';

// Get form data
const webinarTitle = $('1. Form — Webinar URL + Details').item.json['Webinar Title'];
const hostName = $('1. Form — Webinar URL + Details').item.json['Host / Speaker Name'];
const companyName = $('1. Form — Webinar URL + Details').item.json['Company / Brand Name'];
const webinarDate = $('1. Form — Webinar URL + Details').item.json['Webinar Date'];
const ctaLink = $('1. Form — Webinar URL + Details').item.json['CTA Link'];
const recordingUrl = $('1. Form — Webinar URL + Details').item.json['Webinar Recording URL'];

return [{
  json: {
    summary,
    highlights,
    tags,
    webinarTitle,
    hostName,
    companyName,
    webinarDate,
    ctaLink,
    recordingUrl
  }
}];

parameters.text:
=Write a personalized follow-up email for this lead who attended our webinar.

Lead Details:
- First Name: {{ $json.FirstName }}
- Last Name: {{ $json.LastName }}
- Email: {{ $json.Email }}
- Company: {{ $json.Company }}
- Job Title: {{ $json.Title || 'N/A' }}

Webinar Details:
- Webinar Title: {{ $('7. Code — Extract Summary Data').item.json.webinarTitle }}
- Host: {{ $('7. Code — Extract Summary Data').item.json.hostName }}
- Company: {{ $('7. Code — Extract Summary Data').item.json.companyName }}
- Date: {{ $('7. Code — Extract Summary Data').item.json.webinarDate }}
- CTA Link: {{ $('7. Code — Extract Summary Data').item.json.ctaLink }}
- Recording URL: {{ $('7. Code — Extract Summary Data').item.json.recordingUrl }}

Webinar Summary:
{{ $('7. Code — Extract Summary Data').item.json.summary }}

Key Highlights Covered:
{{ $('7. Code — Extract Summary Data').item.json.highlights }}

---

Write a personalized follow-up email following these rules:

1. Address the lead by their first name
2. Reference 2-3 specific things from the webinar highlights that are relevant to someone in their role or industry
3. Keep it conversational and warm — not salesy
4. Include a clear next step with the CTA link
5. Include the recording URL so they can rewatch
6. Total length: 150-200 words — short and easy to read
7. End with the host's name as signature

Return in this exact format:

SUBJECT_LINE:
[Write subject line — 45-55 chars — reference the webinar topic]

PERSONALIZED_INTRO:
[Write 1-2 sentence personalized opening that references their role or company]

EMAIL_BODY:
[Write the full email body — 150-200 words — no subject line — starts with Hi [FirstName],]

parameters.jsCode:
// Parse AI email output
const output = $input.first().json.output || '';

// Extract subject line
const subjectMatch = output.match(/SUBJECT_LINE:\s*([\s\S]*?)(?=\nPERSONALIZED_INTRO:|$)/);
const introMatch = output.match(/PERSONALIZED_INTRO:\s*([\s\S]*?)(?=\nEMAIL_BODY:|$)/);
const bodyMatch = output.match(/EMAIL_BODY:\s*([\s\S]*)$/);

const subjectLine = subjectMatch ? subjectMatch[1].trim() : `Re: ${$('7. Code — Extract Summary Data').item.json.webinarTitle}`;
const personalizedIntro = introMatch ? introMatch[1].trim() : '';
const emailBody = bodyMatch ? bodyMatch[1].trim() : output;

// Get lead data
const leadId = $('8. Salesforce — Query Registered Leads').item.json.Id;
const leadEmail = $('8. Salesforce — Query Registered Leads').item.json.Email;
const leadFirstName = $('8. Salesforce — Query Registered Leads').item.json.FirstName;
const leadLastName = $('8. Salesforce — Query Registered Leads').item.json.LastName;
const leadCompany = $('8. Salesforce — Query Registered Leads').item.json.Company;

// Get webinar data
const webinarTitle = $('7. Code — Extract Summary Data').item.json.webinarTitle;
const companyName = $('7. Code — Extract Summary Data').item.json.companyName;

return [{
  json: {
    subjectLine,
    personalizedIntro,
    emailBody,
    leadId,
    leadEmail,
    leadFirstName,
    leadLastName,
    leadCompany,
    webinarTitle,
    companyName
  }
}];

